import { createContext, memo, PropsWithChildren, useEffect, useMemo, useState } from 'react';
import axios from 'axios';

import { ConfigModel, defaultConfigModel } from '../models/configModel';

export const ConfigContext = createContext<ConfigModel>(defaultConfigModel);

export const ConfigContextProvider = memo((props: PropsWithChildren<unknown>) => {
  const [isLoading, setLoading] = useState(true);
  const [tryAgain, setTryAgain] = useState(false);
  const [firstLoad, setFirstLoad] = useState(true);

  const apiUrl = process.env.REACT_APP_API_URL || defaultConfigModel.apiUrl;
  const buildVersion = process.env.REACT_APP_BUILD_VERSION || defaultConfigModel.buildVersion;

  axios.defaults.baseURL = apiUrl;

  useEffect(() => {
    if (apiUrl.length === 0) {
      console.error('Missing api url');
      return;
    }

    const runAsync = async () => {
      try {
        const request = await fetch(apiUrl + 'api/ready');
        if (request.ok) {
          setLoading(false);
        } else {
          setFirstLoad(false);
          setTryAgain(!tryAgain);
        }
      } catch {
        setFirstLoad(false);
        setTryAgain(!tryAgain);
      }
    };
    // first time - check is the server is up
    isLoading && firstLoad && runAsync();
    // is not the first time - wait 1s to check again if the server is up
    isLoading && !firstLoad && setTimeout(() => runAsync(), 1000);
  }, [apiUrl, firstLoad, tryAgain]);

  const loadingElement = useMemo(() => {
    return (
      <>
        <div className="d-flex justify-content-center m-4">
          <div className="spinner-border" role="status">
            <span className="visually-hidden">Loading...</span>
          </div>
        </div>
        <div className="d-flex justify-content-center">
          <p>server is sleeping, hang tight.</p>
        </div>
      </>
    );
  }, []);

  return (
    <ConfigContext.Provider value={{ ...defaultConfigModel, apiUrl, buildVersion }}>
      {isLoading ? loadingElement : props.children}
    </ConfigContext.Provider>
  );
});
